 53→function filterSections(sections: SectionData[], query: string): SectionData[] {
 54→  if (!query) return sections;
 55→  const lower = query.toLowerCase();
 56→  return sections
 57→    .map(section => ({
 58→      ...section,
 59→      items: section.items.filter(
 60→        item =>
 61→          item.title.toLowerCase().includes(lower) ||
 62→          item.subtitle?.toLowerCase().includes(lower),
 63→      ),
 64→    }))
 65→    .filter(section => section.items.length > 0);
 66→}
 67→
 68→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 69→  if (!query) return colors;
 70→  const lower = query.toLowerCase();
 71→  return colors.filter(
 72→    c =>
 73→      c.title.toLowerCase().includes(lower) ||
 74→      c.subtitle?.toLowerCase().includes(lower),
 75→  );
 76→}
 77→
 78→function flattenItems(sections: SectionData[]): ListItemData[] {
 79→  return sections.flatMap(s => s.items);
 80→}
